// HIBP breacheddomain returns { "alias": ["BreachName", ...] } — alias@domain.
// Diff against workflowStaticData so each (account, breach) pair alerts exactly once.
const DOMAIN = 'example.com';
const resp = $input.first().json;

let mapping = null;
if (resp && !resp.error && typeof resp === 'object' && !Array.isArray(resp)) {
  const entries = Object.entries(resp).filter(([, v]) => Array.isArray(v));
  if (entries.length) mapping = Object.fromEntries(entries);
}

// Demo fallback: canned result imitating the HIBP shape (one old breach the
// static data will already know after the first run, one "new" one).
if (!mapping) {
  mapping = {
    'a.yilmaz':   ['LinkedIn2021', 'DataBrokerAggregate2026'],
    'c.demir':    ['DataBrokerAggregate2026'],
    'svc-marketing': ['DataBrokerAggregate2026'],
    'j.smith':    ['LinkedIn2021'],
  };
}

// Minimal breach metadata (real flow: GET /api/v3/breach/{name}, no auth needed)
const BREACH_META = {
  LinkedIn2021: { breach_date: '2021-06-22', data_classes: ['Email addresses', 'Phone numbers'], verified: true },
  DataBrokerAggregate2026: { breach_date: '2026-06-28', data_classes: ['Email addresses', 'Passwords'], verified: true },
};

const sd = $getWorkflowStaticData('global');
const seen = sd.seen_exposures ?? {};
const newExposures = [];
for (const [alias, breaches] of Object.entries(mapping)) {
  for (const breach of breaches) {
    const key = `${alias}|${breach}`;
    if (seen[key]) continue;
    seen[key] = new Date().toISOString();
    const meta = BREACH_META[breach] ?? {};
    newExposures.push({
      email: `${alias}@${DOMAIN}`,
      alias,
      breach,
      breach_date: meta.breach_date ?? null,
      data_classes: meta.data_classes ?? [],
      passwords_exposed: (meta.data_classes ?? []).includes('Passwords'),
    });
  }
}
sd.seen_exposures = seen;

if (newExposures.length === 0) {
  return [{ json: { new_exposures: false } }];
}
return [{ json: {
  new_exposures: true,
  domain: DOMAIN,
  count: newExposures.length,
  breaches: [...new Set(newExposures.map(e => e.breach))],
  affected_accounts: newExposures,
  reset_candidates: newExposures.filter(e => e.passwords_exposed),
} }];

// Summarize: which resets were requested, which API calls failed,
// and which exposures did NOT get a reset (no password in the breach).
const detection = $('Detect New Exposures').first().json;
const resetResults = $input.all().map((item, i) => {
  const candidate = detection.reset_candidates[i] ?? {};
  return {
    email: candidate.email ?? 'unknown',
    breach: candidate.breach ?? 'unknown',
    reset_requested: !item.json.error,
    error: item.json.error ? String(item.json.error.message ?? item.json.error).slice(0, 200) : null,
  };
});
const noReset = detection.affected_accounts.filter(a => !a.passwords_exposed);

return [{ json: {
  domain: detection.domain,
  breaches: detection.breaches,
  total_new_exposures: detection.count,
  resets: resetResults,
  resets_failed: resetResults.filter(r => !r.reset_requested).length,
  monitored_only: noReset.map(a => `${a.email} (${a.breach}: ${a.data_classes.join(', ') || 'no password data'})`),
} }];

